insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('additional-maths:9-2-definite-integrals-and-areas:mcq:4dd89cec', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'mcq', 'mcq', 1, '{"question": "A region lies partly above and partly below the \\( x \\)-axis. Integrating straight across the whole range gives:", "options": ["Less than the true area, because the parts partly cancel", "Exactly the true area, because the integral handles the negative parts for you", "Always zero", "Double the true area"]}'::jsonb, '{"answer": 0, "explain": "The negative (below-axis) part cancels some of the positive part, so you must split at the roots and add the sizes."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:mcq:91447941', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'mcq', 'mcq', 1, '{"question": "Between the intersection points, \\( y = x + 2 \\) lies above \\( y = x^2 \\). The area between them is \\( \\int_{-1}^{2}(\\ldots)\\,dx \\) where \\( \\ldots \\) is:", "options": ["\\( (x + 2) - x^2 \\)", "\\( x^2 - (x + 2) \\)", "\\( x^2 + x + 2 \\)", "\\( (x + 2)\\,x^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "Top minus bottom: the line \\( (x+2) \\) minus the curve \\( x^2 \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:f04edbdc', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "A definite integral needs a constant of integration \\( +c \\)."}'::jsonb, '{"answer": false, "explain": "The \\( +c \\) appears in \\( F(b) \\) and \\( F(a) \\) and cancels on subtracting, so a definite integral is just \\( F(b) - F(a) \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:bbb716bb', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "\\( \\int_a^b y\\,dx = F(b) - F(a) \\)."}'::jsonb, '{"answer": true, "explain": "Integrate to \\( F(x) \\), then substitute the upper limit and subtract the lower limit."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:2ab94e68', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "A region lying below the \\( x \\)-axis gives a negative definite integral."}'::jsonb, '{"answer": true, "explain": "There \\( y \\) is negative, so the integral is negative; take the modulus for a physical area."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:70733303', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "The limits of a definite integral for an area are the \\( y \\)-values of the boundaries."}'::jsonb, '{"answer": false, "explain": "The limits are always \\( x \\)-values — the \\( x \\)-coordinates of the ordinates or intersection points."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:48b93a10', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "For the area between two curves you integrate the bottom curve minus the top curve."}'::jsonb, '{"answer": false, "explain": "It is top minus bottom; the wrong order gives the negative of the area."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:a1263fce', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "\\( \\int_2^2 (x^2 + 5)\\,dx = 0 \\)."}'::jsonb, '{"answer": true, "explain": "Equal limits give \\( F(2) - F(2) = 0 \\) for any function."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:6589934e', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "If a curve is partly above and partly below the axis, a single integral over the whole range gives the true physical area."}'::jsonb, '{"answer": false, "explain": "The below-axis part is negative and partly cancels the above-axis part, so you must split at the roots and add the sizes."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tf:9082afd8', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tf', 'tf', 1, '{"question": "On an ''exact'' question you may give the area as a rounded decimal."}'::jsonb, '{"answer": false, "explain": "''Exact'' requires a fraction or surd; a decimal alone scores no marks."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:learn:9c7fb398', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'learn', 'mcq', 1, '{"readingTitle": "How do you evaluate a definite integral?", "reading": "<p>A <strong>definite integral</strong> \\( \\int_a^b y\\,dx \\) has two <strong>limits</strong>: a lower limit \\( a \\) and an upper limit \\( b \\). Unlike an indefinite integral it produces a <em>number</em>, not a function — so there is <strong>no</strong> constant of integration.</p>\n            <ul>\n              <li><strong>Step 1.</strong> Integrate as usual and write the result in square brackets with the limits: \\( \\big[F(x)\\big]_a^b \\).</li>\n              <li><strong>Step 2.</strong> Substitute the limits and subtract: \\[ \\int_a^b y\\,dx = F(b) - F(a). \\] Always <strong>upper minus lower</strong>.</li>\n              <li>The \\( +c \\) is not needed — it would appear in both \\( F(b) \\) and \\( F(a) \\) and cancel.</li>\n            </ul>\n            <p><strong>Worked example — evaluate \\( \\int_1^3 (2x + 1)\\,dx \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Integrate: \\( \\big[x^2 + x\\big]_1^3 \\).</td></tr>\n              <tr><td>2. Upper limit \\( x = 3 \\): \\( 3^2 + 3 = 12 \\).</td></tr>\n              <tr><td>3. Lower limit \\( x = 1 \\): \\( 1^2 + 1 = 2 \\).</td></tr>\n              <tr><td>4. Subtract: \\[ \\int_1^3 (2x+1)\\,dx = 12 - 2 = 10. \\]</td></tr>\n            </table>", "question": "Evaluate \\( \\int_0^2 3x^2\\,dx \\).", "options": ["\\( 8 \\)", "\\( 12 \\)", "\\( 24 \\)", "\\( 4 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\big[x^3\\big]_0^2 = 2^3 - 0^3 = 8 \\). Integrate \\( 3x^2 \\) to \\( x^3 \\), then substitute the limits."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:learn:7d8d3f98', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the area between a curve and the x-axis?", "reading": "<p>The area enclosed by a curve, the \\( x \\)-axis and the two vertical lines (<strong>ordinates</strong>) \\( x = a \\) and \\( x = b \\) is \\[ \\text{Area} = \\int_a^b y\\,dx, \\] provided the curve stays <strong>above</strong> the \\( x \\)-axis between those limits. The limits are always the <strong>\\( x \\)-values</strong> of the boundaries.</p>\n            <p><strong>Worked example — area under \\( y = x^2 + 1 \\) from \\( x = 0 \\) to \\( x = 3 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\text{Area} = \\int_0^3 (x^2 + 1)\\,dx = \\big[\\tfrac{x^3}{3} + x\\big]_0^3 \\).</td></tr>\n              <tr><td>2. At \\( x = 3 \\): \\( \\tfrac{27}{3} + 3 = 12 \\).</td></tr>\n              <tr><td>3. At \\( x = 0 \\): \\( 0 + 0 = 0 \\).</td></tr>\n              <tr><td>4. Area \\( = 12 - 0 = 12 \\) square units.</td></tr>\n            </table>\n            <svg viewBox=\"0 0 320 230\" width=\"100%\" style=\"max-width:360px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Curve y equals x squared plus 1 rising left to right, with the region between the curve, the x-axis and the ordinates x equals 0 and x equals 3 shaded\">\n              <polygon points=\"40,190 40,173 82,169 123,156 165,135 207,105 248,67 290,20 290,190\" fill=\"currentColor\" fill-opacity=\"0.18\"/>\n              <line x1=\"40\" y1=\"20\" x2=\"40\" y2=\"205\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <line x1=\"25\" y1=\"190\" x2=\"305\" y2=\"190\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <polygon points=\"40,20 36,30 44,30\" fill=\"currentColor\"/>\n              <polygon points=\"305,190 295,186 295,194\" fill=\"currentColor\"/>\n              <polyline points=\"40,173 82,169 123,156 165,135 207,105 248,67 290,20\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <line x1=\"290\" y1=\"185\" x2=\"290\" y2=\"195\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <g font-size=\"12\" fill=\"currentColor\">\n                <text x=\"40\" y=\"204\" text-anchor=\"middle\">0</text>\n                <text x=\"290\" y=\"204\" text-anchor=\"middle\">3</text>\n                <text x=\"34\" y=\"24\" text-anchor=\"end\">y</text>\n                <text x=\"303\" y=\"186\" text-anchor=\"end\">x</text>\n              </g>\n            </svg>\n            <p>Mark the ordinates, shade the strip, integrate between them, and give the answer in square units.</p>", "question": "The area between \\( y = 3x^2 \\), the \\( x \\)-axis and the ordinates \\( x = 1 \\) and \\( x = 2 \\) is:", "options": ["\\( 7 \\)", "\\( 8 \\)", "\\( 9 \\)", "\\( 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\int_1^2 3x^2\\,dx = \\big[x^3\\big]_1^2 = 8 - 1 = 7 \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:learn:e130adaa', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'learn', 'mcq', 1, '{"readingTitle": "What happens when the region is below the x-axis?", "reading": "<p>Where a curve dips <strong>below</strong> the \\( x \\)-axis, \\( y \\) is negative, so the definite integral comes out <strong>negative</strong>. A physical area cannot be negative — take the <strong>modulus</strong> (drop the sign).</p>\n            <ul>\n              <li>If a region is partly above and partly below the axis, one integral over the whole range gives a <em>partial cancellation</em>, not the true area.</li>\n              <li>Split the range at the <strong>roots</strong> (where \\( y = 0 \\)), work out each piece separately, and add the <em>sizes</em> together.</li>\n            </ul>\n            <p><strong>Worked example — area between \\( y = x^2 - 2x \\) and the \\( x \\)-axis from \\( x = 0 \\) to \\( x = 2 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\int_0^2 (x^2 - 2x)\\,dx = \\big[\\tfrac{x^3}{3} - x^2\\big]_0^2 \\).</td></tr>\n              <tr><td>2. At \\( x = 2 \\): \\( \\tfrac{8}{3} - 4 = -\\tfrac{4}{3} \\); at \\( x = 0 \\): \\( 0 \\).</td></tr>\n              <tr><td>3. Integral \\( = -\\tfrac{4}{3} \\) — negative because the curve is below the axis here.</td></tr>\n              <tr><td>4. Physical area \\( = \\left|-\\tfrac{4}{3}\\right| = \\tfrac{4}{3} \\) square units.</td></tr>\n            </table>", "question": "\\( \\int_{-2}^{2}(x^2 - 4)\\,dx = -\\tfrac{32}{3} \\). What is the physical area between the curve and the \\( x \\)-axis?", "options": ["\\( \\tfrac{32}{3} \\)", "\\( -\\tfrac{32}{3} \\)", "\\( 0 \\)", "\\( \\tfrac{16}{3} \\)"]}'::jsonb, '{"answer": 0, "explain": "The curve is below the axis, so the integral is negative; the physical area is the modulus, \\( \\tfrac{32}{3} \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:learn:2b2a3289', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the area between two curves?", "reading": "<p>The area <strong>enclosed between two curves</strong> is found by integrating the <strong>difference</strong> of the two functions — <strong>top curve minus bottom curve</strong> — between the \\( x \\)-values where they cross: \\[ \\text{Area} = \\int_a^b \\big(y_{\\text{top}} - y_{\\text{bottom}}\\big)\\,dx. \\]</p>\n            <ul>\n              <li><strong>First</strong> find the limits by solving the two equations <strong>simultaneously</strong> — the \\( x \\)-coordinates of the intersection points are \\( a \\) and \\( b \\).</li>\n              <li>Subtracting top \\( - \\) bottom handles curves below the axis automatically, so you rarely need to take a modulus here.</li>\n            </ul>\n            <p><strong>Worked example — area between the line \\( y = x + 2 \\) and the curve \\( y = x^2 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Intersections: \\( x^2 = x + 2 \\Rightarrow x^2 - x - 2 = 0 \\Rightarrow (x-2)(x+1) = 0 \\), so \\( x = -1 \\) and \\( x = 2 \\).</td></tr>\n              <tr><td>2. Between these the line is on top: \\( \\text{Area} = \\int_{-1}^{2}\\big[(x+2) - x^2\\big]\\,dx \\).</td></tr>\n              <tr><td>3. \\( = \\big[\\tfrac{x^2}{2} + 2x - \\tfrac{x^3}{3}\\big]_{-1}^{2} = \\tfrac{10}{3} - \\left(-\\tfrac{7}{6}\\right) \\).</td></tr>\n              <tr><td>4. \\( = \\tfrac{20}{6} + \\tfrac{7}{6} = \\tfrac{27}{6} = \\tfrac{9}{2} \\) square units.</td></tr>\n            </table>\n            <svg viewBox=\"0 0 340 240\" width=\"100%\" style=\"max-width:380px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"A straight line and an upward parabola crossing at the points minus 1, 1 and 2, 4, with the region enclosed between them shaded\">\n              <polygon points=\"66,164 284,56 248,119 211,164 175,191 139,200 103,191 66,164\" fill=\"currentColor\" fill-opacity=\"0.18\"/>\n              <line x1=\"139\" y1=\"20\" x2=\"139\" y2=\"215\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <line x1=\"20\" y1=\"200\" x2=\"330\" y2=\"200\" stroke=\"currentColor\" stroke-width=\"1.4\"/>\n              <polygon points=\"139,20 135,30 143,30\" fill=\"currentColor\"/>\n              <polygon points=\"330,200 320,196 320,204\" fill=\"currentColor\"/>\n              <polyline points=\"30,119 66,164 103,191 139,200 175,191 211,164 248,119 284,56\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <line x1=\"30\" y1=\"182\" x2=\"320\" y2=\"38\" stroke=\"currentColor\" stroke-width=\"1.8\"/>\n              <circle cx=\"66\" cy=\"164\" r=\"3.2\" fill=\"currentColor\"/>\n              <circle cx=\"284\" cy=\"56\" r=\"3.2\" fill=\"currentColor\"/>\n              <g font-size=\"12\" fill=\"currentColor\">\n                <text x=\"60\" y=\"178\" text-anchor=\"end\">(-1, 1)</text>\n                <text x=\"290\" y=\"52\">(2, 4)</text>\n                <text x=\"133\" y=\"24\" text-anchor=\"end\">y</text>\n                <text x=\"328\" y=\"196\" text-anchor=\"end\">x</text>\n              </g>\n            </svg>", "question": "To find the area between \\( y = x + 2 \\) and \\( y = x^2 \\), what is the FIRST thing you do?", "options": ["Solve the equations simultaneously to find the limits", "Integrate each curve separately from \\( x = 0 \\) to \\( x = 10 \\) and subtract", "Add the two functions", "Take the modulus of each curve"]}'::jsonb, '{"answer": 0, "explain": "The limits are the \\( x \\)-values where the curves cross, so you solve them simultaneously first."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:learn:aeb944f5', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'learn', 'mcq', 1, '{"readingTitle": "How do you avoid the classic area traps?", "reading": "<p>Most lost marks on area questions come from a small set of slips. Guard against each one:</p>\n            <ul>\n              <li><strong>Wrong limits.</strong> The limits are always \\( x \\)-values. Using the <em>\\( y \\)-values</em> of the intersection points (e.g. integrating from \\( 1 \\) to \\( 9 \\) instead of from \\( -1 \\) to \\( 2 \\)) is a frequent error.</li>\n              <li><strong>Sign of the subtraction.</strong> For two curves, use top \\( - \\) bottom. Getting it the wrong way round gives a negative answer; you may quote its modulus, but state that it is an area.</li>\n              <li><strong>Negative \"area\".</strong> A region below the axis gives a negative integral — the physical area is the modulus.</li>\n              <li><strong>Symmetry shortcut.</strong> If a region is symmetric about the \\( y \\)-axis (or another line), you may integrate one half and <strong>double</strong> it — but only when the shape really is symmetric, and the limits must match that half.</li>\n              <li><strong>\"Exact\" is a command word.</strong> Leave the area as a fraction or surd; a rounded decimal scores no marks on an \"exact\" question.</li>\n            </ul>", "question": "A student finds the area between two curves that cross at \\( (-1,\\ 1) \\) and \\( (2,\\ 4) \\), integrating from \\( 1 \\) to \\( 4 \\). What went wrong?", "options": ["They used the y-values as the x-limits", "They forgot the constant of integration", "They should have added the curves", "Nothing — those are the correct limits"]}'::jsonb, '{"answer": 0, "explain": "The limits are the \\( x \\)-coordinates \\( -1 \\) and \\( 2 \\); \\( 1 \\) and \\( 4 \\) are the \\( y \\)-values."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:learn:5d9f9591', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'learn', 'mcq', 1, '{"readingTitle": "Which integration facts must you memorise?", "reading": "<p>Definite-integral area questions rely on a few facts you must <strong>memorise</strong> — none of these is on the formula sheet.</p>\n            <ul>\n              <li><strong>Integrate a power:</strong> \\[ \\int x^n\\,dx = \\frac{x^{n+1}}{n+1} + c \\quad (n \\ne -1). \\]</li>\n              <li><strong>Definite integral:</strong> \\( \\int_a^b y\\,dx = \\big[F(x)\\big]_a^b = F(b) - F(a) \\).</li>\n              <li><strong>Area under a curve:</strong> \\( \\text{Area} = \\int_a^b y\\,dx \\) (above the axis).</li>\n              <li><strong>Area between two curves:</strong> \\( \\int_a^b (y_{\\text{top}} - y_{\\text{bottom}})\\,dx \\).</li>\n              <li>\\( \\int_a^a y\\,dx = 0 \\), and swapping the limits changes the sign.</li>\n            </ul>\n            <p><strong>Guardrail:</strong> in this qualification you only integrate <strong>polynomials</strong> — no trig, exponential or log integration, and \\( n \\) is a whole number.</p>", "question": "What is \\( \\int x^3\\,dx \\)?", "options": ["\\( \\frac{x^4}{4} + c \\)", "\\( 3x^2 + c \\)", "\\( \\frac{x^4}{3} + c \\)", "\\( 4x^4 + c \\)"]}'::jsonb, '{"answer": 0, "explain": "Raise the power by one and divide by the new power: \\( \\frac{x^{3+1}}{3+1} = \\frac{x^4}{4} \\), plus \\( c \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:misc:0569b237', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Two curves cross at \\( (1,\\ 1) \\) and \\( (5,\\ 9) \\), so integrate from \\( 1 \\) to \\( 9 \\).</p><p><strong>✅ The correct idea:</strong> The limits are the \\( x \\)-coordinates, \\( 1 \\) and \\( 5 \\). A weak answer uses the \\( y \\)-values \\( 1 \\) and \\( 9 \\) as the x-limits; a strong answer integrates from \\( x = 1 \\) to \\( x = 5 \\).</p>", "question": "Curves meet at \\( (1,\\ 1) \\) and \\( (5,\\ 9) \\). The limits are:", "options": ["\\( x = 1 \\) to \\( x = 5 \\)", "\\( 1 \\) to \\( 9 \\)", "\\( y = 1 \\) to \\( y = 9 \\)", "\\( 0 \\) to \\( 9 \\)"]}'::jsonb, '{"answer": 0, "explain": "Use the \\( x \\)-coordinates of the intersections, \\( 1 \\) and \\( 5 \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:misc:3ade309c', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The integral came out as \\( -\\tfrac{32}{3} \\), so the area is \\( -\\tfrac{32}{3} \\).</p><p><strong>✅ The correct idea:</strong> An area cannot be negative. A weak answer gives a negative number as a physical area; a strong answer notes the region is below the axis and takes the modulus, \\( \\tfrac{32}{3} \\).</p>", "question": "An integral for an area gives \\( -\\tfrac{32}{3} \\). The physical area is:", "options": ["\\( \\tfrac{32}{3} \\)", "\\( -\\tfrac{32}{3} \\)", "\\( 0 \\)", "impossible to find"]}'::jsonb, '{"answer": 0, "explain": "Take the modulus: \\( \\tfrac{32}{3} \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:misc:91a2b608', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For the area between two curves, integrate \\( \\int (y_{\\text{bottom}} - y_{\\text{top}})\\,dx \\).</p><p><strong>✅ The correct idea:</strong> Subtract top minus bottom. A weak answer subtracts the wrong way and gets a negative; a strong answer uses \\( y_{\\text{top}} - y_{\\text{bottom}} \\) (or quotes the modulus and calls it an area).</p>", "question": "The safe integrand for an area between curves is:", "options": ["top \\( - \\) bottom", "bottom \\( - \\) top", "top \\( + \\) bottom", "either, they are equal"]}'::jsonb, '{"answer": 0, "explain": "Top minus bottom gives a positive area directly."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:misc:512b1fb6', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( \\int_1^3 (2x+1)\\,dx = 3^2 + 3 = 12 \\).</p><p><strong>✅ The correct idea:</strong> You must subtract the value at the lower limit too. A weak answer stops at \\( F(3) \\); a strong answer computes \\( F(3) - F(1) = 12 - 2 = 10 \\).</p>", "question": "\\( \\int_1^3 (2x+1)\\,dx \\) equals:", "options": ["\\( 10 \\)", "\\( 12 \\)", "\\( 2 \\)", "\\( 14 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( F(3) - F(1) = 12 - 2 = 10 \\)."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:misc:daabbf7e', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The exact area is about \\( 1.33 \\).</p><p><strong>✅ The correct idea:</strong> ''Exact'' forbids a decimal. A weak answer rounds; a strong answer leaves the fraction, e.g. \\( \\tfrac{4}{3} \\).</p>", "question": "Which is an ''exact'' area?", "options": ["\\( \\tfrac{4}{3} \\)", "\\( 1.33 \\)", "\\( 1.3 \\)", "about \\( 1.33 \\)"]}'::jsonb, '{"answer": 0, "explain": "The fraction \\( \\tfrac{4}{3} \\) is exact; the decimals are not."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tips:ee956ae8', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show your working — the exact-area ladder", "reading": "<p><strong>0 marks:</strong> writing \\( 1.33 \\) with no integral shown on an \"exact\" question.</p><p><strong>Partial:</strong> \\( \\int_0^2 (x^2 - 2x)\\,dx = \\big[\\tfrac{x^3}{3} - x^2\\big]_0^2 \\) but the answer left negative or as a decimal.</p><p><strong>Full marks:</strong> the integral in brackets, limits substituted, and the exact area \\( \\tfrac{4}{3} \\) (modulus taken, stated as an area). Each line earns a mark, so a slip costs one mark, not all of them.</p>", "question": "On an ''exact'' area question, the safest final answer is:", "options": ["A fraction such as \\( \\tfrac{4}{3} \\), with working shown", "A decimal rounded to two decimal places, such as \\( 1.33 \\)", "Just the rounded number", "The negative integral value"]}'::jsonb, '{"answer": 0, "explain": "Exact form with visible working scores the method and accuracy marks."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tips:fc094027', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Detailed reasoning'' — every step must be visible", "reading": "<p>Definite-integral area questions are often flagged <em>\"In this question you must show detailed reasoning.\"</em> A correct answer straight from a calculator''s integral function scores <strong>0</strong> — you must show the integration in brackets, the substitution of the limits, and the subtraction. Read the limits off carefully: they are \\( x \\)-values, not \\( y \\)-values.</p>", "question": "On a ''detailed reasoning'' area question, a correct answer with no working:", "options": ["Scores no marks — the method must be shown", "Scores full marks as long as the final number is correct", "Scores half marks", "Is fine if you used a calculator"]}'::jsonb, '{"answer": 0, "explain": "Detailed reasoning requires the full analytical method; a calculator answer alone scores nothing."}'::jsonb),
('additional-maths:9-2-definite-integrals-and-areas:tips:5d31e16d', 'additional-maths', 'additional-maths:9-2-definite-integrals-and-areas', '9.2 Definite Integrals and Areas', 'tips', 'mcq', 1, '{"readingTitle": "tip — Area between two curves — the reliable routine", "reading": "<p>1. Solve the two equations simultaneously to find the intersection \\( x \\)-values — these are your limits. 2. Decide which curve is on top between them. 3. Integrate \\( y_{\\text{top}} - y_{\\text{bottom}} \\) between the limits. 4. Give the exact answer in square units. Getting the subtraction the wrong way round only flips the sign, so if you get a negative, quote its modulus and label it an area.</p>", "question": "The correct order for an area-between-curves question is:", "options": ["Intersections → top minus bottom → integrate between the x-limits", "Integrate each curve first, then find where they intersect afterwards", "Add the curves → integrate → round", "Differentiate → subtract → square-root"]}'::jsonb, '{"answer": 0, "explain": "Find the limits from the intersections, then integrate top minus bottom between them."}'::jsonb),
